const $=id=>document.getElementById(id);
function show(id){document.querySelectorAll('.screen').forEach(s=>s.classList.remove('active'));$(id).classList.add('active');document.querySelectorAll('.nav').forEach(b=>b.classList.toggle('active',b.dataset.screen===id));}
document.querySelectorAll('.nav').forEach(b=>b.onclick=()=>show(b.dataset.screen));
document.addEventListener('click',e=>{const t=e.target.closest('[data-target]');if(t)show(t.dataset.target)});
['primary','accent','side'].forEach(id=>$(id).oninput=()=>{document.documentElement.style.setProperty('--primary',$('primary').value);document.documentElement.style.setProperty('--accent',$('accent').value);document.documentElement.style.setProperty('--sidebar',$('side').value);});
$('batchRows').innerHTML=employees.map(e=>`<tr><td><div class="avatar">${e[1]}</div></td><td><strong>${e[0]}</strong></td><td>${e[2]}</td><td>${e[3]}</td><td>${e[4]}</td><td>${e[6]}</td><td>${e[7]}</td><td>${e[8]}</td><td>${e[9]}</td><td>${e[16]}</td><td><strong>${e[10]}</strong></td><td><strong style="color:var(--accent)">${e[19]}</strong></td><td><span class="badge ${e[29]==='Anomalie'?'danger':'ok'}">${e[29]==='Anomalie'?'Photo/CNPS':'OK'}</span></td><td><button class="row-btn" data-target="payslip">Ouvrir</button></td></tr>`).join('');
$('stateRows').innerHTML=employees.map(e=>`<tr>${e.map((v,i)=>i===1?`<td><div class="avatar">${v}</div></td>`:i===29?`<td><span class="badge ${v==='Anomalie'?'danger':v==='Validé'?'ok':'warn'}">${v}</span></td>`:`<td>${v}</td>`).join('')}</tr>`).join('');
